// Find all input fields on the page to understand the env var form structure
Array.from(document.querySelectorAll('input, button')).filter(el => {
  const text = (el.textContent || el.value || el.placeholder || '').toLowerCase();
  return text.includes('key') || text.includes('value') || text.includes('add') || text.includes('new') || el.type === 'text';
}).map(el => ({tag: el.tagName, type: el.type, placeholder: el.placeholder, value: el.value?.substring(0,40), text: el.textContent?.trim()?.substring(0,40), name: el.name, id: el.id})).slice(0,20)

// Check if PAPERCLIP_API_URL already exists
const allKeys = Array.from(document.querySelectorAll('input[name="key"]')).map(i => i.value);
JSON.stringify({keys: allKeys, hasPaperclip: allKeys.includes('PAPERCLIP_API_URL')})

// Click the + Add button
const addBtn = Array.from(document.querySelectorAll('button')).find(b => b.textContent.trim() === '+ Add');
addBtn ? (addBtn.click(), 'clicked') : 'not found'

// Look for any new empty key input that appeared after clicking + Add
const emptyKeyInputs = Array.from(document.querySelectorAll('input[name="key"]')).filter(i => i.value === '');
emptyKeyInputs.map(i => ({id: i.id, value: i.value, placeholder: i.placeholder}))

