// Find the new row with placeholder NODE_ENV and its corresponding value input
const keyInput = document.querySelector('input#key-lrueifyhuwa8au2qhyvumju0');
// Find the value textarea/input in the same row
const row = keyInput?.closest('tr, .env-row, [wire\\:key], li, div[class*="row"], div[class*="flex"]');
const rowInfo = row ? {tag: row.tagName, class: row.className.substring(0,100), html: row.innerHTML.substring(0,300)} : 'no row found';
JSON.stringify(rowInfo)

// Find the new key input and use Livewire to set its value
const keyInput = document.querySelector('input[placeholder="NODE_ENV"]');
// Trigger native input event to update Livewire
const nativeInputValueSetter = Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype, 'value').set;
nativeInputValueSetter.call(keyInput, 'PAPERCLIP_API_URL');
keyInput.dispatchEvent(new Event('input', { bubbles: true }));
keyInput.dispatchEvent(new Event('change', { bubbles: true }));
'key set: ' + keyInput.value

// The new row key ID is key-lrueifyhuwa8au2qhyvumju0
// Find corresponding value input - usually has id value-{same-uuid}
const keyId = 'key-lrueifyhuwa8au2qhyvumju0';
const uuid = keyId.replace('key-', '');
const valueInput = document.getElementById('value-' + uuid) || document.querySelector('textarea[id*="' + uuid + '"]') || document.querySelector('input[id*="value-lrueifyhuwa8au2qhyvumju0"]');
valueInput ? ({id: valueInput.id, tag: valueInput.tagName, value: valueInput.value}) : 'not found'

// Find all inputs/textareas near the PAPERCLIP_API_URL key input
const keyInput = document.querySelector('input[placeholder="NODE_ENV"]');
const parent = keyInput?.parentElement?.parentElement?.parentElement;
if (parent) {
  const inputs = Array.from(parent.querySelectorAll('input, textarea')).map(i => ({id: i.id, tag: i.tagName, name: i.name, value: i.value, placeholder: i.placeholder}));
  JSON.stringify(inputs);
} else 'no parent'

const valueInput = document.getElementById('value-vawkdlkq2qi65iobbyaxpkf0');
const nativeInputValueSetter = Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype, 'value').set;
nativeInputValueSetter.call(valueInput, 'https://mc.designflow.app');
valueInput.dispatchEvent(new Event('input', { bubbles: true }));
valueInput.dispatchEvent(new Event('change', { bubbles: true }));
'value set: ' + valueInput.value

// Find the Save/Add button near the new row
const keyInput = document.querySelector('input[placeholder="NODE_ENV"]');
const parent = keyInput?.parentElement?.parentElement?.parentElement;
if (parent) {
  const buttons = Array.from(parent.querySelectorAll('button')).map(b => ({text: b.textContent.trim().substring(0,40), type: b.type, disabled: b.disabled}));
  JSON.stringify(buttons);
} else 'no parent'

// Click the Save button in the new row
const keyInput = document.querySelector('input[placeholder="NODE_ENV"]');
const parent = keyInput?.parentElement?.parentElement?.parentElement;
const saveBtn = parent?.querySelector('button[type="submit"]');
saveBtn ? (saveBtn.click(), 'clicked save') : 'no save button'

// Check if PAPERCLIP_API_URL now exists in the env vars list
setTimeout(() => {}, 1500);
const allKeys = Array.from(document.querySelectorAll('input[name="key"]')).map(i => i.value);
JSON.stringify({hasPaperclipApiUrl: allKeys.includes('PAPERCLIP_API_URL'), count: allKeys.length})

const keyInput = Array.from(document.querySelectorAll('input[name="key"]')).find(i => i.value === 'PAPERCLIP_API_URL');
const parent = keyInput?.parentElement?.parentElement?.parentElement;
const valueInput = parent?.querySelector('input[name="value"]');
JSON.stringify({key: keyInput?.value, value: valueInput?.value})

// Find Deploy button
const deployBtns = Array.from(document.querySelectorAll('button')).filter(b => b.textContent.toLowerCase().includes('deploy') || b.textContent.toLowerCase().includes('redeploy'));
deployBtns.map(b => ({text: b.textContent.trim().substring(0,50), disabled: b.disabled}))

