// Check for confirmation dialog or deployment status
const dialogs = Array.from(document.querySelectorAll('[role="dialog"], .modal, [class*="modal"], [class*="dialog"]'));
const confirmBtns = Array.from(document.querySelectorAll('button')).filter(b => b.textContent.toLowerCase().includes('confirm') || b.textContent.toLowerCase().includes('yes') || b.textContent.toLowerCase().includes('start'));
JSON.stringify({dialogs: dialogs.length, confirmBtns: confirmBtns.map(b => b.textContent.trim().substring(0,40))})

// Check deployment status
const statusEl = document.querySelector('[class*="status"], [class*="badge"], .deployment-status, h1, h2');
const logLines = Array.from(document.querySelectorAll('[class*="log"], pre, code')).slice(0,3).map(el => el.textContent.trim().substring(0,100));
JSON.stringify({title: document.title, status: statusEl?.textContent?.trim()?.substring(0,80), logs: logLines})

// Check latest log lines and status
const logLines = Array.from(document.querySelectorAll('[class*="log"], pre, code')).map(el => el.textContent.trim()).filter(t => t.length > 0);
const last5 = logLines.slice(-5).map(l => l.substring(0,120));
JSON.stringify({title: document.title, last5})

