  headers: { 'Authorization': 'Bearer 8|fxWNNsogVMo765M2sZxRhVnCEK21Im976WZXE13Z91dc8ad8' }
}).then(r => r.json()).then(d => { window._deps = d.data ? d.data.map(dep => ({uuid: dep.uuid, status: dep.status, created_at: dep.created_at})) : d; }).catch(e => { window._deps = 'err: '+e.message; });
'sent'

// Find the compose file / docker compose content on the page
const textareas = Array.from(document.querySelectorAll('textarea, pre, code, [class*="compose"], [class*="docker"]'));
textareas.map(el => ({tag: el.tagName, id: el.id, class: el.className.substring(0,60), content: el.textContent.substring(0,200)})).filter(el => el.content.length > 10).slice(0,5)

// Get the full application data including docker compose
fetch('http://178.156.180.212:8000/api/v1/applications/jihoc2f68xmgi2gfomhhr9g3', {
  headers: { 'Authorization': 'Bearer 8|fxWNNsogVMo765M2sZxRhVnCEK21Im976WZXE13Z91dc8ad8' }
}).then(r => r.json()).then(d => {
  window._ocmcApp = {
    docker_compose_raw: d.docker_compose_raw?.substring(0,1000),
    docker_compose_location: d.docker_compose_location,
    build_pack: d.build_pack,
    custom_docker_run_options: d.custom_docker_run_options
  };
}).catch(e => { window._ocmcApp = 'err: '+e.message; });
'sent'

// List all apps in OpenClaw environment
fetch('http://178.156.180.212:8000/api/v1/projects/cfe31cda-75eb-4fa5-a979-419dc3fd90ed', {
  headers: { 'Authorization': 'Bearer 8|fxWNNsogVMo765M2sZxRhVnCEK21Im976WZXE13Z91dc8ad8' }
}).then(r => r.json()).then(d => {
  window._ocProject = d;
}).catch(e => { window._ocProject = 'err: '+e.message; });
'sent'

const d = window._ocProject;
if (d && d.environments) {
  const env = d.environments[0];
  const apps = [...(env.applications || []), ...(env.services || [])];
  JSON.stringify(apps.map(a => ({uuid: a.uuid, name: a.name, status: a.status})));
} else JSON.stringify(Object.keys(d || {}))

