JSON.stringify({inputs, buttons})

// Find the execute container command Livewire component
const wireComponents = Array.from(document.querySelectorAll('[wire\\:id]')).map(el => ({
  wireId: el.getAttribute('wire:id'),
  tag: el.tagName,
  class: el.className.substring(0,80),
  hasCommandInput: !!el.querySelector('[wire\\:model*="command"], [wire\\:model*="cmd"], textarea')
}));
JSON.stringify(wireComponents)

// Find the execute-container-command component specifically
const wireComponents = Array.from(document.querySelectorAll('[wire\\:id]'));
const execComponent = wireComponents.find(el => {
  const html = el.innerHTML;
  return html.includes('execute') || html.includes('container') || html.includes('command') || el.querySelector('select[id*="container"]');
});
execComponent ? JSON.stringify({wireId: execComponent.getAttribute('wire:id'), html: execComponent.innerHTML.substring(0, 500)}) : 'not found'

// Find the container select element and its parent wire component
const containerSelect = document.querySelector('select[id*="container"]');
const wireParent = containerSelect?.closest('[wire\\:id]');
wireParent ? wireParent.getAttribute('wire:id') : 'not found'

// Walk up from container select to find wire:id attribute
const sel = document.querySelector('select[id*="container"]');
let el = sel;
let wireId = null;
for (let i = 0; i < 15; i++) {
  if (!el) break;
  const wid = el.getAttribute('wire:id');
  if (wid) { wireId = wid; break; }
  el = el.parentElement;
}
wireId || 'not found'

