// Find the Livewire terminal component fresh
const all = window.Livewire.all();
const execComp = all.find(c => {
  try {
    return Object.keys(c.snapshot?.data || {}).includes('selected_container');
  } catch { return false; }
});
if (execComp) {
  const sel = document.querySelector('select[name="container"]');
  const openclawVal = sel?.options[3]?.value;
  window._termCompId = execComp.id;
  window._openclawVal = openclawVal;
  'found comp: ' + execComp.id + ' openclaw: ' + openclawVal?.substring(0,30);
} else 'not found'

const comp = window.Livewire.find('Hsnnlk8nrHsiqlfKDwWh');
const snap = comp.snapshot;
const sel = document.querySelector('select[name="container"]');
const openclawVal = sel.options[3].value;
const csrfToken = document.querySelector('meta[name="csrf-token"]')?.content;

// Livewire v3 update format
const payload = {
  components: [{
    snapshot: JSON.stringify(snap),
    updates: { selected_container: openclawVal },
    calls: []
  }]
};

fetch('/livewire/update', {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'X-Livewire': 'true',
    'X-CSRF-TOKEN': csrfToken,
    'Accept': 'text/html, application/xhtml+xml',
    'Referer': window.location.href
  },
  credentials: 'same-origin',
  body: JSON.stringify(payload)
}).then(r => {
  window._lwUpdate = {status: r.status, headers: Object.fromEntries(r.headers.entries())};
  return r.text();
}).then(t => { window._lwUpdate.body = t.substring(0,300); }).catch(e => { window._lwUpdate = 'err: '+e.message; });
'sent'
